export function isSafeUrl(url: string): boolean {
	try {
		const parsed = new URL(url)
		return parsed.protocol === "http:" || parsed.protocol === "https:"
	} catch {
		return false
	}
}

"use client"

import { ExternalLink, Youtube } from "lucide-react"
import { useState } from "react"
import { cn } from "@/lib/utils"
import { isSafeUrl } from "@/utils/url"

interface YouTubeEmbedProps {
	url: string
	className?: string
	title?: string
}

/**
 * Extracts YouTube video ID from various YouTube URL formats
 * Supports: youtube.com/watch?v=, youtu.be/, youtube.com/embed/, youtube.com/shorts/
 */
function extractYouTubeVideoId(url: string): string | null {
	if (!url) return null

	try {
		const urlObj = new URL(url)
		const hostname = urlObj.hostname.toLowerCase()

		// Standard youtube.com URLs
		if (hostname.includes("youtube.com")) {
			// /watch?v= format
			const videoId = urlObj.searchParams.get("v")
			if (videoId) return videoId

			// /embed/ format
			const embedMatch = urlObj.pathname.match(/\/embed\/([^/?]+)/)
			if (embedMatch) return embedMatch[1]

			// /shorts/ format
			const shortsMatch = urlObj.pathname.match(/\/shorts\/([^/?]+)/)
			if (shortsMatch) return shortsMatch[1]
		}

		// Short youtu.be URLs
		if (hostname.includes("youtu.be")) {
			const id = urlObj.pathname.slice(1).split(/[?&]/)[0]
			if (id) return id
		}
	} catch {
		// Invalid URL, try regex fallback
		const regexPatterns = [
			/(?:youtube\.com\/watch\?v=|youtu\.be\/|youtube\.com\/embed\/|youtube\.com\/shorts\/)([a-zA-Z0-9_-]{11})/,
		]

		for (const pattern of regexPatterns) {
			const match = url.match(pattern)
			if (match) return match[1]
		}
	}

	return null
}

/**
 * Checks if a URL is a valid YouTube URL
 */
export function isYouTubeUrl(url: string): boolean {
	return extractYouTubeVideoId(url) !== null
}

export function YouTubeEmbed({ url, className, title }: YouTubeEmbedProps) {
	const videoId = extractYouTubeVideoId(url)

	if (!videoId) {
		return (
			<div
				className={cn(
					"relative aspect-video w-full overflow-hidden rounded-lg bg-muted flex items-center justify-center p-4",
					className,
				)}
			>
				<a
					href={isSafeUrl(url) ? url : "#"}
					target="_blank"
					rel="noopener noreferrer"
					className="inline-flex items-center gap-2 text-primary hover:underline text-sm"
				>
					<ExternalLink className="h-4 w-4" />
					Open video in new tab
				</a>
			</div>
		)
	}

	return (
		<div
			className={cn(
				"relative aspect-video w-full overflow-hidden rounded-lg bg-black",
				className,
			)}
		>
			<iframe
				src={`https://www.youtube.com/embed/${videoId}?rel=0&modestbranding=1`}
				title={title || "YouTube video player"}
				allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
				allowFullScreen
				sandbox="allow-scripts allow-same-origin allow-presentation"
				className="absolute inset-0 h-full w-full"
				loading="lazy"
			/>
		</div>
	)
}

export function YouTubeThumbnail({
	url,
	className,
}: {
	url: string
	className?: string
}) {
	const videoId = extractYouTubeVideoId(url)
	const [imgSrc, setImgSrc] = useState(
		videoId
			? `https://img.youtube.com/vi/${videoId}/maxresdefault.jpg`
			: "",
	)

	if (!videoId) {
		return (
			<div
				className={cn(
					"relative aspect-video w-full overflow-hidden rounded-lg bg-muted flex items-center justify-center",
					className,
				)}
			>
				<Youtube aria-hidden="true" className="h-8 w-8 text-muted-foreground" />
			</div>
		)
	}

	return (
		<div
			className={cn(
				"relative aspect-video w-full overflow-hidden rounded-lg",
				className,
			)}
		>
			<img
				src={imgSrc}
				alt="Video thumbnail"
				className="absolute inset-0 h-full w-full object-cover"
				loading="lazy"
				onError={() => {
					setImgSrc(
						`https://img.youtube.com/vi/${videoId}/mqdefault.jpg`,
					)
				}}
			/>
			<div className="absolute inset-0 flex items-center justify-center">
				<div className="rounded-full bg-red-600 p-3 shadow-lg">
					<Youtube aria-hidden="true" className="h-6 w-6 text-white" />
				</div>
			</div>
		</div>
	)
}

"use client"

import { Link } from "@tanstack/react-router"
import {
	ArrowRight,
	CheckCircle2,
	ClipboardCheck,
	Clock,
	Dumbbell,
	Edit3,
	Eye,
	Hash,
	Lock,
	MapPin,
	Target,
	Timer,
	Trophy,
} from "lucide-react"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Card } from "@/components/ui/card"
import { cn } from "@/lib/utils"
import type { DivisionDescription } from "@/server-fns/competition-workouts-fns"
import { getGoogleMapsUrl, hasAddressData } from "@/utils/address"

export interface SubmissionStatus {
	hasSubmitted: boolean
	canSubmit: boolean
}

interface CompetitionWorkoutCardProps {
	eventId: string
	slug: string
	trackOrder: number
	name: string
	scheme: string // e.g. "time", "amrap", etc. from DB enum
	description: string | null // Default description
	roundsToScore: number | null
	pointsMultiplier: number | null
	movements?: Array<{ id: string; name: string }>
	tags?: Array<{ id: string; name: string }>
	divisionDescriptions: DivisionDescription[]
	sponsorName?: string
	sponsorLogoUrl?: string | null
	selectedDivisionId?: string
	isRegistered?: boolean
	submissionStatus?: SubmissionStatus | null
	timeCap?: number | null // in seconds
	venue?: {
		id: string
		name: string
		address: {
			streetLine1?: string
			city?: string
			stateProvince?: string
			postalCode?: string
			countryCode?: string
		} | null
	} | null
	schedule?: {
		startTime: string
		endTime: string | null
		heatCount: number
		venueName: string | null
		divisions: string[]
	} | null
}

function formatTime(seconds: number): string {
	const m = Math.floor(seconds / 60)
	const s = seconds % 60
	return `${m}:${s.toString().padStart(2, "0")}`
}

function getSchemeLabel(scheme: string, timeCap?: number | null): string {
	if (scheme === "time" || scheme === "time-with-cap") {
		return timeCap ? "For Time (Capped)" : "For Time"
	}
	if (scheme === "amrap") return "AMRAP"
	if (scheme === "emom") return "EMOM"
	if (scheme === "load") return "For Load"
	return scheme.replace(/-/g, " ").toUpperCase()
}

function getCtaConfig(
	isRegistered?: boolean,
	submissionStatus?: SubmissionStatus | null,
) {
	if (!isRegistered) {
		return {
			label: "View Details",
			icon: ArrowRight,
			variant: "outline" as const,
			badge: null,
		}
	}

	if (!submissionStatus) {
		// Registered but no submission tracking (in-person comp)
		return {
			label: "View Details",
			icon: ArrowRight,
			variant: "outline" as const,
			badge: null,
		}
	}

	const { hasSubmitted, canSubmit } = submissionStatus

	if (hasSubmitted && canSubmit) {
		return {
			label: "Edit Submission",
			icon: Edit3,
			variant: "outline" as const,
			badge: {
				label: "Submitted",
				className:
					"bg-green-100 text-green-700 border-green-200 dark:bg-green-950/30 dark:text-green-400 dark:border-green-900",
			},
		}
	}

	if (hasSubmitted && !canSubmit) {
		return {
			label: "View Submission",
			icon: Eye,
			variant: "outline" as const,
			badge: {
				label: "Submitted",
				className:
					"bg-green-100 text-green-700 border-green-200 dark:bg-green-950/30 dark:text-green-400 dark:border-green-900",
			},
		}
	}

	if (!hasSubmitted && canSubmit) {
		return {
			label: "Submit Score",
			icon: ClipboardCheck,
			variant: "default" as const,
			badge: null,
		}
	}

	// !hasSubmitted && !canSubmit ‚Äî window closed, never submitted
	return {
		label: "Submission Closed",
		icon: Lock,
		variant: "outline" as const,
		badge: null,
	}
}

export function CompetitionWorkoutCard({
	eventId,
	slug,
	trackOrder,
	name,
	scheme,
	description,
	roundsToScore,
	pointsMultiplier,
	movements,
	tags,
	divisionDescriptions,
	sponsorName,
	sponsorLogoUrl,
	selectedDivisionId,
	isRegistered,
	submissionStatus,
	timeCap,
	venue,
	schedule,
}: CompetitionWorkoutCardProps) {
	// Get the selected division's scale info (if any)
	// Only show scale for the explicitly selected division - no fallback
	const targetDivision =
		selectedDivisionId && selectedDivisionId !== "default"
			? divisionDescriptions.find((d) => d.divisionId === selectedDivisionId)
			: null

	// Division scale is shown separately from base description
	const divisionScale = targetDivision?.description?.trim() || null
	const divisionLabel = targetDivision?.divisionLabel || null

	const formattedTimeCap = timeCap ? formatTime(timeCap) : null

	const schemeLabel = getSchemeLabel(scheme, timeCap)
	const hasMovementsOrTags =
		(movements && movements.length > 0) || (tags && tags.length > 0)

	const cta = getCtaConfig(isRegistered, submissionStatus)
	const CtaIcon = cta.icon

	return (
		<Card className="overflow-hidden border-l-4 border-l-primary/40 hover:border-l-primary transition-all">
			<div className="flex flex-col md:flex-row">
				{/* Hero Number & Header Section */}
				<div className="flex-1 p-4 sm:p-6">
					{/* Header - stacked on mobile, inline on desktop */}
					<div className="mb-4 sm:mb-6">
						{/* Mobile: stacked layout */}
						<div className="flex flex-col sm:flex-row sm:items-start sm:justify-between sm:gap-4">
							<div className="flex items-baseline gap-3 sm:items-start sm:gap-4">
								<span className="text-4xl sm:text-6xl font-black text-primary/70 leading-none select-none">
									{trackOrder.toString().padStart(2, "0")}
								</span>
								<div className="sm:pt-1">
									<div className="flex items-center gap-2">
										<h3 className="text-xl sm:text-2xl font-bold tracking-tight">
											{name}
										</h3>
										{cta.badge && (
											<Badge
												variant="outline"
												className={cn(
													"text-[10px] sm:text-xs font-medium",
													cta.badge.className,
												)}
											>
												<CheckCircle2 className="h-3 w-3 mr-1" />
												{cta.badge.label}
											</Badge>
										)}
									</div>
									{sponsorName && (
										<div className="flex items-center gap-2 mt-1">
											{sponsorLogoUrl && (
												<img
													src={sponsorLogoUrl}
													alt={sponsorName}
													className="h-5 sm:h-6 w-auto object-contain"
												/>
											)}
											{!sponsorLogoUrl && (
												<span className="text-xs font-medium text-muted-foreground uppercase tracking-wider">
													Presented by {sponsorName}
												</span>
											)}
										</div>
									)}
								</div>
							</div>

							{/* Desktop CTA Button */}
							<Button
								variant={cta.variant}
								size="sm"
								asChild
								className="hidden shrink-0 sm:flex"
							>
								<Link
									to="/compete/$slug/workouts/$eventId"
									params={{ slug, eventId }}
								>
									{cta.label}
									<CtaIcon className="ml-2 h-4 w-4" />
								</Link>
							</Button>
						</div>
					</div>

					{/* Specs Row */}
					<div className="flex flex-wrap gap-2 mb-4 sm:mb-6">
						{formattedTimeCap && (
							<div
								className={cn(
									"inline-flex items-center gap-1 px-2 py-0.5 sm:gap-1.5 sm:px-3 sm:py-1 rounded-full text-xs sm:text-sm font-medium border",
									scheme === "time-with-cap"
										? "bg-red-50 text-red-700 border-red-200 dark:bg-red-950/30 dark:text-red-400 dark:border-red-900"
										: "bg-secondary text-secondary-foreground border-transparent",
								)}
							>
								<Timer className="h-3 w-3 sm:h-4 sm:w-4" />
								{formattedTimeCap} Cap
							</div>
						)}
						<div className="inline-flex items-center gap-1 px-2 py-0.5 sm:gap-1.5 sm:px-3 sm:py-1 rounded-full text-xs sm:text-sm font-medium bg-secondary text-secondary-foreground">
							<Target className="h-3 w-3 sm:h-4 sm:w-4" />
							{schemeLabel}
						</div>
						{pointsMultiplier && pointsMultiplier !== 100 && (
							<div className="inline-flex items-center gap-1 px-2 py-0.5 sm:gap-1.5 sm:px-3 sm:py-1 rounded-full text-xs sm:text-sm font-medium bg-blue-50 text-blue-700 border border-blue-200 dark:bg-blue-950/30 dark:text-blue-400 dark:border-blue-900">
								<Trophy className="h-3 w-3 sm:h-4 sm:w-4" />
								{pointsMultiplier / 100}x
							</div>
						)}
						{roundsToScore && roundsToScore > 1 && (
							<div className="inline-flex items-center gap-1 px-2 py-0.5 sm:gap-1.5 sm:px-3 sm:py-1 rounded-full text-xs sm:text-sm font-medium bg-secondary text-secondary-foreground">
								<Hash className="h-3 w-3 sm:h-4 sm:w-4" />
								{roundsToScore} Rounds
							</div>
						)}
						{schedule && (
							<div className="inline-flex items-center gap-1 px-2 py-0.5 sm:gap-1.5 sm:px-3 sm:py-1 rounded-full text-xs sm:text-sm font-medium bg-emerald-50 text-emerald-700 border border-emerald-200 dark:bg-emerald-950/30 dark:text-emerald-400 dark:border-emerald-900">
								<Clock className="h-3 w-3 sm:h-4 sm:w-4" />
								{schedule.startTime}
								{schedule.endTime && ` ‚Äì ${schedule.endTime}`}
								{schedule.heatCount > 1 && ` ¬∑ ${schedule.heatCount} heats`}
							</div>
						)}
					</div>

					{/* Venue Section */}
					<div className="mb-4 sm:mb-6">
						{venue?.address && hasAddressData(venue.address) ? (
							(() => {
								const mapsUrl = getGoogleMapsUrl(venue.address)
								return (
									<div className="flex flex-wrap items-center gap-2 sm:gap-3">
										<div className="flex items-center gap-1.5 sm:gap-2 text-xs sm:text-sm text-muted-foreground">
											<MapPin className="h-3.5 w-3.5 sm:h-4 sm:w-4 shrink-0" />
											<span className="font-medium">{venue.name}</span>
										</div>
										{mapsUrl && (
											<Button
												variant="outline"
												size="sm"
												asChild
												className="h-7 text-xs sm:h-8 sm:text-sm"
											>
												<a
													href={mapsUrl}
													target="_blank"
													rel="noopener noreferrer"
												>
													Get Directions
												</a>
											</Button>
										)}
									</div>
								)
							})()
						) : (
							<div className="flex items-center gap-1.5 sm:gap-2 text-xs sm:text-sm text-muted-foreground italic">
								<MapPin className="h-3.5 w-3.5 sm:h-4 sm:w-4" />
								<span>Venue to be announced</span>
							</div>
						)}
					</div>

					{/* Content Grid */}
					<div
						className={cn(
							"grid gap-4 sm:gap-6",
							hasMovementsOrTags ? "md:grid-cols-12" : "grid-cols-1",
						)}
					>
						{/* Description - Takes up majority */}
						<div
							className={cn(
								hasMovementsOrTags ? "md:col-span-8" : "col-span-1",
							)}
						>
							<div className="prose prose-sm max-w-none dark:prose-invert space-y-4">
								{/* Base workout description */}
								<p className="whitespace-pre-wrap text-sm sm:text-base leading-relaxed">
									{description || (
										<span className="italic text-muted-foreground">
											Details to be announced.
										</span>
									)}
								</p>

								{/* Division-specific scale info */}
								{divisionScale && (
									<div className="border-t pt-3 mt-3">
										<div className="flex items-start gap-2">
											<Badge
												variant="secondary"
												className="shrink-0 text-xs font-medium"
											>
												{divisionLabel || "Division"}
											</Badge>
											<p className="whitespace-pre-wrap text-sm leading-relaxed text-muted-foreground">
												{divisionScale}
											</p>
										</div>
									</div>
								)}
							</div>
						</div>

						{/* Side Panel for Movements ("Ingredients") */}
						{hasMovementsOrTags && (
							<div className="md:col-span-4 border-t md:border-t-0 md:border-l pt-3 sm:pt-4 md:pt-0 md:pl-6">
								{movements && movements.length > 0 && (
									<div>
										<h4 className="text-xs font-bold uppercase tracking-wider text-muted-foreground mb-2 sm:mb-3 flex items-center gap-2">
											<Dumbbell className="h-3.5 w-3.5" />
											Movements
										</h4>
										<ul className="space-y-1.5 sm:space-y-2">
											{movements.map((m) => (
												<li
													key={m.id}
													className="text-xs sm:text-sm font-medium text-foreground/90 flex items-center justify-between"
												>
													{m.name}
												</li>
											))}
										</ul>
									</div>
								)}

								{tags && tags.length > 0 && (
									<div className="mt-4 sm:mt-6">
										<h4 className="text-xs font-bold uppercase tracking-wider text-muted-foreground mb-2 sm:mb-3">
											Tags
										</h4>
										<div className="flex flex-wrap gap-1.5">
											{tags.map((tag) => (
												<Badge
													key={tag.id}
													variant="secondary"
													className="text-xs font-normal"
												>
													{tag.name}
												</Badge>
											))}
										</div>
									</div>
								)}
							</div>
						)}
					</div>

					{/* Mobile CTA - full width at bottom */}
					<Button
						variant={cta.variant}
						size="lg"
						asChild
						className="w-full mt-4 sm:hidden"
					>
						<Link
							to="/compete/$slug/workouts/$eventId"
							params={{ slug, eventId }}
						>
							{cta.label}
							<CtaIcon className="ml-2 h-4 w-4" />
						</Link>
					</Button>
				</div>
			</div>
		</Card>
	)
}

import { beforeEach, describe, expect, it, vi } from "vitest"
import { FakeDrizzleDb } from "@repo/test-utils"
import {
	getVideoSubmissionFn,
	submitVideoFn,
} from "@/server-fns/video-submission-fns"

// Mock the database
const mockDb = new FakeDrizzleDb()

vi.mock("@/db", () => ({
	getDb: vi.fn(() => mockDb),
}))

// Create test sessions
const mockAuthenticatedSession = {
	userId: "test-user-123",
	user: {
		id: "test-user-123",
		email: "test@example.com",
	},
	teams: [
		{
			id: "team-1",
			permissions: [],
		},
	],
}

// Mock auth - default to authenticated
vi.mock("@/utils/auth", () => ({
	getSessionFromCookie: vi.fn(() => Promise.resolve(mockAuthenticatedSession)),
}))

// Mock TanStack createServerFn to make server functions directly callable in tests
vi.mock("@tanstack/react-start", () => ({
	createServerFn: () => {
		return {
			inputValidator: (validator: (data: unknown) => unknown) => ({
				handler: (fn: (ctx: { data: unknown }) => Promise<unknown>) => {
					// Return a wrapper that validates input then calls handler
					return async (ctx: { data: unknown }) => {
						// Run validation - will throw on invalid input
						const validatedData = validator(ctx.data)
						return fn({ data: validatedData })
					}
				},
			}),
		}
	},
}))

// Import mocked getSessionFromCookie so we can change its behavior in tests
import { getSessionFromCookie } from "@/utils/auth"

// Helper to set mock session with proper type coercion
const setMockSession = (session: unknown) => {
	vi.mocked(getSessionFromCookie).mockResolvedValue(
		session as Awaited<ReturnType<typeof getSessionFromCookie>>,
	)
}

// Factory for creating test competitions
function createTestCompetition(
	overrides?: Partial<{
		id: string
		competitionType: "in_person" | "online"
	}>,
) {
	return {
		id: overrides?.id ?? `comp-${Math.random().toString(36).slice(2, 8)}`,
		competitionType: overrides?.competitionType ?? "online",
		...overrides,
	}
}

// Factory for creating test registrations
function createTestRegistration(
	overrides?: Partial<{
		id: string
		eventId: string
		userId: string
		divisionId: string | null
	}>,
) {
	return {
		id: overrides?.id ?? `reg-${Math.random().toString(36).slice(2, 8)}`,
		eventId: overrides?.eventId ?? "comp-1",
		userId: overrides?.userId ?? "test-user-123",
		divisionId: overrides?.divisionId ?? "div-rx",
		...overrides,
	}
}

// Factory for creating test competition events
function createTestCompetitionEvent(
	overrides?: Partial<{
		competitionId: string
		trackWorkoutId: string
		submissionOpensAt: Date | null
		submissionClosesAt: Date | null
	}>,
) {
	return {
		competitionId: overrides?.competitionId ?? "comp-1",
		trackWorkoutId: overrides?.trackWorkoutId ?? "tw-1",
		submissionOpensAt: overrides?.submissionOpensAt ?? null,
		submissionClosesAt: overrides?.submissionClosesAt ?? null,
		...overrides,
	}
}

// Factory for creating test workouts
function createTestWorkout(
	overrides?: Partial<{
		id: string
		name: string
		scheme: string
		scoreType: string | null
		timeCap: number | null
		tiebreakScheme: string | null
		repsPerRound: number | null
	}>,
) {
	return {
		id: overrides?.id ?? `wk-${Math.random().toString(36).slice(2, 8)}`,
		name: overrides?.name ?? "Test Workout",
		scheme: overrides?.scheme ?? "time",
		scoreType: overrides?.scoreType ?? "min",
		timeCap: overrides?.timeCap ?? null,
		tiebreakScheme: overrides?.tiebreakScheme ?? null,
		repsPerRound: overrides?.repsPerRound ?? null,
		...overrides,
	}
}

// Factory for creating test track workouts
function createTestTrackWorkout(
	overrides?: Partial<{
		id: string
		trackId: string
		workoutId: string
	}>,
) {
	return {
		id: overrides?.id ?? `tw-${Math.random().toString(36).slice(2, 8)}`,
		trackId: overrides?.trackId ?? "track-1",
		workoutId: overrides?.workoutId ?? "wk-1",
		...overrides,
	}
}

// Factory for creating test video submissions
function createTestVideoSubmission(
	overrides?: Partial<{
		id: string
		registrationId: string
		trackWorkoutId: string
		userId: string
		videoUrl: string
		notes: string | null
		submittedAt: Date
		updatedAt: Date
	}>,
) {
	const now = new Date()
	return {
		id: overrides?.id ?? `sub-${Math.random().toString(36).slice(2, 8)}`,
		registrationId: overrides?.registrationId ?? "reg-1",
		trackWorkoutId: overrides?.trackWorkoutId ?? "tw-1",
		userId: overrides?.userId ?? "test-user-123",
		videoUrl: overrides?.videoUrl ?? "https://youtube.com/watch?v=test",
		notes: overrides?.notes ?? null,
		submittedAt: overrides?.submittedAt ?? now,
		updatedAt: overrides?.updatedAt ?? now,
		...overrides,
	}
}

// Factory for creating test scores
function createTestScore(
	overrides?: Partial<{
		id: string
		userId: string
		competitionEventId: string
		scoreValue: number | null
		status: string
		scheme: string
		secondaryValue: number | null
		tiebreakValue: number | null
	}>,
) {
	return {
		id: overrides?.id ?? `score-${Math.random().toString(36).slice(2, 8)}`,
		userId: overrides?.userId ?? "test-user-123",
		competitionEventId: overrides?.competitionEventId ?? "tw-1",
		scoreValue: overrides?.scoreValue ?? 300000,
		status: overrides?.status ?? "scored",
		scheme: overrides?.scheme ?? "time",
		secondaryValue: overrides?.secondaryValue ?? null,
		tiebreakValue: overrides?.tiebreakValue ?? null,
		...overrides,
	}
}

