/**
 * Address formatting and normalization utilities
 */

import type { Address, LocationBadgeDisplay } from "@/types/address"

/**
 * US state name to abbreviation mapping
 */
const US_STATE_ABBREVIATIONS: Record<string, string> = {
	alabama: "AL",
	alaska: "AK",
	arizona: "AZ",
	arkansas: "AR",
	california: "CA",
