	"west virginia": "WV",
	wisconsin: "WI",
	wyoming: "WY",
	"district of columbia": "DC",
}

/**
 * Country name to ISO 3166-1 alpha-2 code mapping
 */
const COUNTRY_CODE_MAP: Record<string, string> = {
	"united states": "US",
	"united states of america": "US",
	usa: "US",
	america: "US",
	canada: "CA",
	"united kingdom": "GB",
	uk: "GB",
	"great britain": "GB",
	england: "GB",
	scotland: "GB",
	wales: "GB",
	"northern ireland": "GB",
	australia: "AU",
	"new zealand": "NZ",
	ireland: "IE",
	mexico: "MX",
	germany: "DE",
	france: "FR",
	spain: "ES",
	italy: "IT",
	netherlands: "NL",
	belgium: "BE",
	switzerland: "CH",
	austria: "AT",
