	finland: "FI",
	poland: "PL",
	portugal: "PT",
	greece: "GR",
	czech: "CZ",
	"czech republic": "CZ",
	iceland: "IS",
	brazil: "BR",
	argentina: "AR",
	chile: "CL",
	japan: "JP",
	china: "CN",
	"south korea": "KR",
	india: "IN",
	singapore: "SG",
	"hong kong": "HK",
	philippines: "PH",
	thailand: "TH",
	vietnam: "VN",
	malaysia: "MY",
	indonesia: "ID",
	"south africa": "ZA",
	israel: "IL",
	"saudi arabia": "SA",
	"united arab emirates": "AE",
	uae: "AE",
	dubai: "AE",
	turkey: "TR",
	russia: "RU",
	ukraine: "UA",
}

/**
 * Country code to display name mapping
 */
const COUNTRY_DISPLAY_NAMES: Record<string, string> = {
	US: "United States",
	CA: "Canada",
	GB: "United Kingdom",
	AU: "Australia",
	NZ: "New Zealand",
	IE: "Ireland",
	MX: "Mexico",
	DE: "Germany",
	FR: "France",
	ES: "Spain",
	IT: "Italy",
	NL: "Netherlands",
	BE: "Belgium",
	CH: "Switzerland",
	AT: "Austria",
	DK: "Denmark",
	SE: "Sweden",
	NO: "Norway",
	FI: "Finland",
	PL: "Poland",
	PT: "Portugal",
	GR: "Greece",
